import java.util.ArrayList;
import java.util.List;

class Expedicion {
    private String destino;
    private int duracionDias;

    public Expedicion(String destino, int duracionDias) {
        this.destino = destino;
        this.duracionDias = duracionDias;
    }

    public String getDestino() { return destino; }
    public int getDuracionDias() { return duracionDias; }

    public String toString() {
        return destino + " (" + duracionDias + " días)";
    }
}

public class BuqueInvestigacion {
    private String nombre;
    private List<Expedicion> expediciones; // Relación 1 a *

    public BuqueInvestigacion(String nombre) {
        this.nombre = nombre;
        this.expediciones = new ArrayList<>();
    }

    public void agregarExpedicion(Expedicion e) {
        expediciones.add(e);       // Añadir
    }

    public void eliminarExpedicion(int i) {
        expediciones.remove(i);    // Eliminar
    }

    public Expedicion getExpedicion(int i) {
        return expediciones.get(i); // Acceder
    }

    public int totalExpediciones() {
        return expediciones.size(); // Contar
    }

    public void listarExpediciones() {
        System.out.println("=== " + nombre + " ===");
        for (int i = 0; i < expediciones.size(); i++) {
            System.out.println("  [" + i + "] " + expediciones.get(i));
        }
        System.out.println("Total: " + expediciones.size() + "\n");
    }

    public static void main(String[] args) {
        BuqueInvestigacion b = new BuqueInvestigacion("Hespérides");

        b.agregarExpedicion(new Expedicion("Antártida", 90));
        b.agregarExpedicion(new Expedicion("Pacífico", 45));
        b.agregarExpedicion(new Expedicion("Caribe", 30));

        b.listarExpediciones();
        // Salida:
        // === Hespérides ===
        //   [0] Antártida (90 días)
        //   [1] Pacífico (45 días)
        //   [2] Caribe (30 días)
        // Total: 3

        b.eliminarExpedicion(2);   // Eliminar la última
        System.out.println("Total tras eliminar: " + b.totalExpediciones());
        // Salida: Total tras eliminar: 2
    }
}
